mapper.select:
SELECT m.id AS id, m.trip_id AS trip_id, m.user_id AS user_id, m.role AS role, m.status AS status, m.joined_at AS joined_at, t.owner_user_id AS owner_user_id FROM trip.trip_members m JOIN trip.trips t ON t.id = m.trip_id WHERE m.trip_id = #{tripId}
AND m.status = #{status}
ORDER BY CASE WHEN m.user_id = t.owner_user_id THEN 0 ELSE 1 END, m.joined_at ASC, m.id ASC

mapper.sql:
FROM trip.trips t
JOIN trip.trip_members m
  ON m.trip_id = t.id
  AND m.user_id = #{userId}
  AND m.status = 'ACTIVE'
WHERE t.status != 'DELETED'

  AND t.status = #{status}


  AND t.owner_user_id = #{userId}


  AND t.owner_user_id != #{userId}

mapper.select:
SELECT id, trip_id, created_by_user_id, invitee_user_id, invite_code, invite_token_hash, status, expires_at, accepted_by_user_id, accepted_at, revoked_at, created_at FROM trip.trip_invites WHERE trip_id = #{tripId}
AND status = #{status}
ORDER BY created_at DESC, id DESC
